  std::cout << "  KnownFPClasses: " << k1.KnownFPClasses << "\n";
  std::cout << "  SignBit: " << (k1.SignBit ? (*k1.SignBit ? "true" : "false") : "nullopt") << "\n";

  // Test case 2: knownNot(fcPositive) when we know it's not NaN
  KnownFPClass k2;
  k2.KnownFPClasses = fcNegative;  // We know it's negative
  k2.SignBit = std::nullopt;

  std::cout << "\nTest 2 - Before knownNot(fcPositive):\n";
  std::cout << "  KnownFPClasses: " << k2.KnownFPClasses << "\n";
  std::cout << "  SignBit: " << (k2.SignBit ? (*k2.SignBit ? "true" : "false") : "nullopt") << "\n";

  k2.knownNot(fcPositive);

  std::cout << "Test 2 - After knownNot(fcPositive):\n";
  std::cout << "  KnownFPClasses: " << k2.KnownFPClasses << "\n";
  std::cout << "  SignBit: " << (k2.SignBit ? (*k2.SignBit ? "true" : "false") : "nullopt") << "\n";

  return 0;
}
