#include <iostream>
#include <optional>
#include <cstdint>

enum FPClassTest : uint32_t {
  fcNone = 0,
  fcNan = 1 << 0,
  fcSNan = 1 << 1,
  fcQNan = 1 << 2,
  fcInf = 1 << 3,
  fcPosInf = 1 << 4,
  fcNegInf = 1 << 5,
  fcZero = 1 << 6,
  fcPosZero = 1 << 7,
  fcNegZero = 1 << 8,
  fcSubnormal = 1 << 9,
  fcPositive = 1 << 10,
  fcNegative = 1 << 11,
  fcFinite = fcZero | fcSubnormal | fcPositive | fcNegative,
  fcAllFlags = fcNan | fcInf | fcZero | fcSubnormal | fcPositive | fcNegative
};

struct KnownFPClass {
  FPClassTest KnownFPClasses;
  std::optional<bool> SignBit;

  bool isKnownNever(FPClassTest Test) const {
    return (KnownFPClasses & Test) == fcNone;
  }

  void knownNot(FPClassTest RuleOut) {
    KnownFPClasses = KnownFPClasses & ~RuleOut;
    if (isKnownNever(fcNan) && !SignBit) {
      if (isKnownNever(fcNegative))
        SignBit = false;
      else if (isKnownNever(fcPositive))
        SignBit = true;
    }
  }

  void signBitMustBeZero() {
    KnownFPClasses &= (fcPositive | fcNan);
    SignBit = false;
  }

  void signBitMustBeOne() {
    KnownFPClasses &= (fcNegative | fcNan);
    SignBit = true;
  }
};

int main() {
  // Test: Start with SignBit = true, then knownNot(fcNegative)
  KnownFPClass k;
  k.KnownFPClasses = fcNegative;  // We know it's negative
  k.SignBit = true;  // We know sign bit is 1

  std::cout << "Before knownNot(fcNegative):\n";
  std::cout << "  KnownFPClasses: " << k.KnownFPClasses << "\n";
  std::cout << "  SignBit: " << (k.SignBit ? (*k.SignBit ? "true" : "false") : "nullopt") << "\n";
  std::cout << "  isKnownNever(fcNegative): " << k.isKnownNever(fcNegative) << "\n";

  k.knownNot(fcNegative);

  std::cout << "\nAfter knownNot(fcNegative):\n";
  std::cout << "  KnownFPClasses: " << k.KnownFPClasses << "\n";
  std::cout << "  SignBit: " << (k.SignBit ? (*k.SignBit ? "true" : "false") : "nullopt") << "\n";
  std::cout << "  isKnownNever(fcNegative): " << k.isKnownNever(fcNegative) << "\n";

  // This is a contradiction! SignBit is true but value is not negative.
  // The value would have to be -0.0, but -0.0 is in fcNegative!

  return 0;
}
EOF"}

